  1→import { stat } from 'node:fs/promises';
  2→import { homedir } from 'node:os';
  3→import { dirname, join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { Agent, LineParser, SessionFinder } from '../agent.interface.ts';
  6→import type {
  7→  ParsedLine,
  8→  ParserOptions,
  9→  ProjectInfo,
 10→  SessionFile,
 11→} from '../../core/types.ts';
 12→import { truncateByLines, formatMultiline } from '../../utils/text.ts';
 13→import { formatToolUse } from '../../utils/format-tool.ts';
 14→import { CodexSessionCache } from './session-cache.ts';
 15→import {
 16→  buildCodexSubagentFiles,
 17→  extractCodexSubagentIds,
 18→} from '../../codex/watch-builder.ts';
 19→
 20→/**
 21→ * Codex Session Finder
 22→ * 目錄結構: ~/.codex/sessions/YYYY/MM/DD/rollout-*.jsonl
 23→ */
 24→class CodexSessionFinder implements SessionFinder {
 25→  private _baseDir: string;
 26→  private _cache: CodexSessionCache;
 27→
 28→  constructor() {
 29→    this._baseDir = join(homedir(), '.codex', 'sessions');
 30→    this._cache = new CodexSessionCache(this._baseDir);
 31→  }
 32→
 33→  getBaseDir(): string {
 34→    return this._baseDir;
 35→  }
 36→
 37→  /**
 38→   * 設定 baseDir（用於測試）
 39→   * 同時會重置 cache 使用新的目錄
 40→   */
 41→  setBaseDir(dir: string): void {
 42→    this._baseDir = dir;
 43→    this._cache = new CodexSessionCache(dir);
 44→  }
 45→
 46→  /**
 47→   * 取得 cache 實例（用於 findLatestInProject）
 48→   */
 49→  private get cache(): CodexSessionCache {
 50→    return this._cache;
 51→  }
 52→
 53→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
 54→    const glob = new Glob('**/*.jsonl');
 55→    const files: { path: string; mtime: Date }[] = [];
 56→
 57→    for await (const file of glob.scan({
 58→      cwd: this._baseDir,
 59→      absolute: true,
 60→    })) {
 61→      // 只匹配 rollout-*.jsonl
 62→      const filename = file.split('/').pop() || '';
 63→      if (!filename.startsWith('rollout-')) continue;
 64→
 65→      // 如果有 project filter，做模糊比對（對 Codex 來說是日期過濾）
 66→      if (options.project) {
 67→        const pattern = options.project.toLowerCase();
 68→        if (!file.toLowerCase().includes(pattern)) continue;
 69→      }
 70→
 71→      try {
 72→        const stats = await stat(file);
 73→        files.push({ path: file, mtime: stats.mtime });
 74→      } catch {
 75→        // 忽略無法讀取的檔案
 76→      }
 77→    }
 78→
 79→    if (files.length === 0) return null;
 80→
 81→    // 按修改時間排序，取最新的
 82→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
 83→
 84→    const latest = files[0];
 85→    if (!latest) return null;
 86→
 87→    return {
 88→      path: latest.path,
 89→      mtime: latest.mtime,
 90→      agentType: 'codex',
 91→    };
 92→  }
 93→
 94→  /**
 95→   * 依 session ID 查找 session 檔案
 96→   * 檔名格式：rollout-{timestamp}-{sessionId}.jsonl
 97→   * 支援匹配：session ID（ULID）、時間戳
 98→   */
 99→  async findBySessionId(
100→    sessionId: string,
101→    options: { project?: string }
102→  ): Promise<SessionFile | null> {
103→    const glob = new Glob('**/*.jsonl');
104→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
105→
106→    // UUID 格式的正規表達式（用於提取 session ID）
107→    const ulidPattern =
108→      /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\.jsonl$/i;
109→
110→    for await (const file of glob.scan({
111→      cwd: this._baseDir,
112→      absolute: true,
113→    })) {
114→      const filename = file.split('/').pop() || '';
115→      if (!filename.startsWith('rollout-')) continue;
116→
117→      // project filter
118→      if (options.project) {
119→        const pattern = options.project.toLowerCase();
120→        if (!file.toLowerCase().includes(pattern)) continue;
121→      }
122→
123→      // 從檔名提取 session ID（ULID 部分）
124→      const ulidMatch = filename.match(ulidPattern);
125→      const extractedSessionId = ulidMatch?.[1] || '';
126→
127→      // 提取時間戳部分（rollout- 和 session ID 之間的部分）
128→      // rollout-2025-11-03T20-42-15-019a49bd-...
129→      const withoutPrefix = filename.replace(/^rollout-/, '');
130→      const timestampPart = extractedSessionId
131→        ? withoutPrefix.replace(`-${extractedSessionId}.jsonl`, '')
132→        : '';
133→
134→      // 計算匹配優先級
135→      let priority = 0;
136→      const searchTerm = sessionId.toLowerCase();
137→
138→      // 1. 對 session ID 進行匹配
139→      if (extractedSessionId) {
140→        const normalizedId = extractedSessionId.toLowerCase();
141→        if (normalizedId === searchTerm) {
142→          priority = 6; // 精確匹配 session ID
143→        } else if (normalizedId.startsWith(searchTerm)) {
144→          priority = 5; // 前綴匹配 session ID
145→        } else if (normalizedId.includes(searchTerm)) {
146→          priority = 4; // 包含匹配 session ID
147→        }
148→      }
149→
150→      // 2. 對時間戳進行匹配（如果 session ID 沒有匹配到）
151→      if (priority === 0 && timestampPart) {
152→        const normalizedTimestamp = timestampPart.toLowerCase();
153→        if (normalizedTimestamp === searchTerm) {
154→          priority = 3; // 精確匹配時間戳
155→        } else if (normalizedTimestamp.startsWith(searchTerm)) {
156→          priority = 2; // 前綴匹配時間戳
157→        } else if (normalizedTimestamp.includes(searchTerm)) {
158→          priority = 1; // 包含匹配時間戳
159→        }
160→      }
161→
162→      if (priority === 0) continue;
163→
164→      try {
165→        const stats = await stat(file);
166→        candidates.push({ path: file, mtime: stats.mtime, priority });
167→      } catch {
168→        // 忽略無法讀取的檔案
169→      }
170→    }
171→
172→    if (candidates.length === 0) return null;
173→
174→    // 排序：優先級降序 > mtime 降序
175→    candidates.sort((a, b) => {
176→      if (b.priority !== a.priority) return b.priority - a.priority;
177→      return b.mtime.getTime() - a.mtime.getTime();
178→    });
179→
180→    const best = candidates[0];
181→    if (!best) return null;
182→
183→    return {
184→      path: best.path,
185→      mtime: best.mtime,
186→      agentType: 'codex',
187→    };
188→  }
189→
190→  /**
191→   * 從 session 檔案取得專案資訊（用於 auto-switch）
192→   * 解析 session_meta 取得 cwd
193→   */
194→  async getProjectInfo(sessionPath: string): Promise<ProjectInfo | null> {
195→    try {
196→      const content = await Bun.file(sessionPath).text();
197→      const firstLine = content.split('\n')[0];
198→      if (!firstLine) return null;
199→
200→      const meta = JSON.parse(firstLine);
201→      if (meta.type === 'session_meta' && meta.payload?.cwd) {
202→        return {
203→          projectDir: meta.payload.cwd,
204→          displayName: meta.payload.cwd,
205→        };
206→      }
207→    } catch {
208→      // 忽略解析錯誤
209→    }
210→    return null;
211→  }
212→
213→  /**
214→   * 在指定專案範圍內找最新的 session（用於 auto-switch）
215→   * @param cwd - 專案目錄路徑
216→   */
217→  async findLatestInProject(cwd: string): Promise<SessionFile | null> {
218→    return this.cache.getLatestByCwd(cwd);
219→  }
220→
221→  /**
222→   * 找到 subagent 檔案
223→   * - 有 subagentId：用 UUID glob 在所有日期目錄查找
224→   * - 無 subagentId：從最新 session 掃描 subagent IDs，回傳最新的 subagent 檔案
225→   *
226→   * 已知限制：無 subagentId 時，findLatest() 不保證回傳主 session（可能回傳 subagent 檔案）。
227→   * 若 extractCodexSubagentIds 回傳空陣列，會回傳 null。
228→   */
229→  async findSubagent(options: {
230→    project?: string;
231→    subagentId?: string;
232→  }): Promise<SessionFile | null> {
233→    if (options.subagentId) {
234→      // 有 subagentId：用 UUID glob 精確查找
235→      return this._findSubagentById(options.subagentId, options.project);
236→    } else {
237→      // 無 subagentId：從最新 session 掃描 subagent IDs
238→      return this._findLatestSubagent(options.project);
239→    }
240→  }
241→
242→  /**
243→   * 依 subagentId（UUID 前綴或完整 UUID）在所有日期目錄查找 subagent 檔案
244→   */
245→  private async _findSubagentById(
246→    subagentId: string,
247→    project?: string
248→  ): Promise<SessionFile | null> {
249→    const glob = new Glob('**/*.jsonl');
250→    const candidates: { path: string; mtime: Date }[] = [];
251→
252→    for await (const file of glob.scan({
253→      cwd: this._baseDir,
254→      absolute: true,
255→    })) {
256→      const filename = file.split('/').pop() || '';
257→      if (!filename.startsWith('rollout-')) continue;
258→
259→      // project filter
260→      if (project) {
261→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
262→      }
263→
264→      // 包含 subagentId（大小寫不敏感）
265→      if (!filename.toLowerCase().includes(subagentId.toLowerCase())) continue;
266→
267→      try {
268→        const stats = await stat(file);
269→        candidates.push({ path: file, mtime: stats.mtime });
270→      } catch {
271→        // 忽略無法讀取的檔案
272→      }
273→    }
274→
275→    if (candidates.length === 0) return null;
276→
277→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
278→    const best = candidates[0];
279→    if (!best) return null;
280→
281→    return { path: best.path, mtime: best.mtime, agentType: 'codex' };
282→  }
283→
284→  /**
285→   * 掃描所有 session，從最新的開始找第一個含 subagent IDs 的，回傳最新的 subagent 檔案
286→   *
287→   * 注意：findLatest() 不區分主 session 和 subagent session（依 mtime 排序）。
288→   * 此方法改為迭代所有候選 session，跳過不含 spawn_agent 事件的（通常是 subagent 本身）。
289→   */
290→  private async _findLatestSubagent(
291→    project?: string
292→  ): Promise<SessionFile | null> {
293→    const glob = new Glob('**/*.jsonl');
294→    const candidates: { path: string; mtime: Date }[] = [];
295→
296→    for await (const file of glob.scan({
297→      cwd: this._baseDir,
298→      absolute: true,
299→    })) {
300→      const filename = file.split('/').pop() || '';
301→      if (!filename.startsWith('rollout-')) continue;
302→
303→      if (project) {
304→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
305→      }
306→
307→      try {
308→        const stats = await stat(file);
309→        candidates.push({ path: file, mtime: stats.mtime });
310→      } catch {
311→        // 忽略無法讀取的檔案
312→      }
313→    }
314→
315→    if (candidates.length === 0) return null;
316→
317→    // 由新到舊排序，優先從最新的 session 找 subagent
318→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
319→
320→    for (const candidate of candidates) {
321→      const agentIds = await extractCodexSubagentIds(candidate.path);
322→      if (agentIds.length === 0) continue;
323→
324→      const dateDir = dirname(candidate.path);
325→      const subFiles = await buildCodexSubagentFiles(dateDir, agentIds);
326→      if (subFiles.length === 0) continue;
327→
328→      subFiles.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
329→      return subFiles[0] ?? null;
330→    }
331→
332→    return null;
333→  }
334→}
