336→/**
337→ * Codex JSONL 解析器
338→ */
339→class CodexLineParser implements LineParser {
340→  private verbose: boolean;
341→
342→  constructor(options: ParserOptions = { verbose: false }) {
343→    this.verbose = options.verbose;
344→  }
345→
346→  parse(line: string): ParsedLine | null {
347→    if (!line.trim()) return null;
348→
349→    try {
350→      const data = JSON.parse(line);
351→      const timestamp = data.timestamp || '';
352→      const formatted = this.format(data);
353→
354→      // 空內容不輸出
355→      if (!formatted) return null;
356→
357→      // 決定顯示類型
358→      const type = this.getDisplayType(data);
359→
360→      // 取得 tool name（僅 function_call 類型）
361→      const toolName = this.getToolName(data);
362→
363→      return {
364→        type,
365→        timestamp,
366→        raw: data,
367→        formatted,
368→        ...(toolName && { toolName }),
369→      };
370→    } catch {
371→      return null;
372→    }
373→  }
374→
375→  /**
376→   * 取得 tool 名稱（僅 function_call 類型）
377→   */
378→  private getToolName(data: Record<string, unknown>): string | undefined {
379→    const type = data.type as string;
380→    if (type !== 'response_item') return undefined;
381→
382→    const payload = data.payload as Record<string, unknown>;
383→    if (payload.type !== 'function_call') return undefined;
384→
385→    return payload.name as string | undefined;
386→  }
387→
388→  /**
389→   * 根據資料內容決定顯示類型
390→   */
391→  private getDisplayType(data: Record<string, unknown>): string {
392→    const type = data.type as string;
393→
394→    if (type === 'session_meta') return 'session_meta';
395→
396→    if (type === 'response_item') {
397→      const payload = data.payload as Record<string, unknown>;
398→      const subType = payload.type as string;
399→
400→      if (subType === 'message') {
401→        const role = payload.role as string;
402→        return role || 'message';
403→      }
404→      if (subType === 'function_call') return 'function_call';
405→      if (subType === 'function_call_output') return 'output';
406→      if (subType === 'reasoning') return 'reasoning';
407→    }
408→
409→    return type || 'unknown';
410→  }
411→
412→  private format(data: Record<string, unknown>): string {
413→    const type = data.type as string;
414→
415→    switch (type) {
416→      case 'session_meta': {
417→        const payload = data.payload as Record<string, unknown>;
418→        return `Session: ${payload.cwd || 'unknown'} (v${payload.cli_version || '?'})`;
419→      }
420→
421→      case 'response_item': {
422→        const payload = data.payload as Record<string, unknown>;
423→        const subType = payload.type as string;
424→
425→        switch (subType) {
426→          case 'message': {
427→            const _role = payload.role as string;
428→            const content = payload.content as Array<{
429→              type: string;
430→              text?: string;
431→            }>;
432→            const text =
433→              content?.find(
434→                (c) => c.type === 'input_text' || c.type === 'output_text'
435→              )?.text || '';
436→            if (!text.trim()) return '';
437→            const preview = truncateByLines(text, { verbose: this.verbose });
438→            // 不再重複顯示 role，由 pretty-formatter 處理
439→            return formatMultiline(preview);
440→          }
441→
442→          case 'function_call': {
443→            const name = payload.name as string;
444→            const argsStr = payload.arguments as string;
445→            let args: Record<string, unknown> = {};
446→            try {
447→              args = JSON.parse(argsStr);
448→            } catch {
449→              /* ignore */
450→            }
451→            return formatToolUse(name, args, { verbose: this.verbose });
452→          }
453→
454→          case 'function_call_output': {
455→            const outputStr = payload.output as string;
456→            let output: { output?: string; metadata?: { exit_code?: number } } =
457→              {};
458→            try {
459→              output = JSON.parse(outputStr);
460→            } catch {
461→              /* ignore */
462→            }
463→            const exitCode = output.metadata?.exit_code;
464→            const content = output.output || '';
465→            // 沒內容且 exit code 正常就不顯示
466→            if (!content && (exitCode === undefined || exitCode === 0))
467→              return '';
468→            const exitInfo =
469→              exitCode !== undefined && exitCode !== 0
470→                ? ` (exit: ${exitCode})`
471→                : '';
472→            if (!content) return `[OUTPUT${exitInfo}]`;
473→            const preview = truncateByLines(content, { verbose: this.verbose });
474→            return `${exitInfo ? `[exit: ${exitCode}]` : ''}${formatMultiline(preview)}`;
475→          }
476→
477→          case 'reasoning': {
478→            const summary = payload.summary as
479→              | Array<{ type: string; text?: string }>
480→              | undefined;
481→            const text =
482→              summary?.find((s) => s.type === 'summary_text')?.text || '';
483→            if (!text) return '';
484→            const preview = truncateByLines(text, { verbose: this.verbose });
485→            return preview;
486→          }
487→
488→          // 忽略的子類型
489→          case 'ghost_snapshot':
490→            return '';
491→
492→          default:
493→            return '';
494→        }
495→      }
496→
497→      case 'event_msg': {
498→        const payload = data.payload as Record<string, unknown>;
499→        const eventType = payload.type as string;
500→
501→        switch (eventType) {
502→          case 'token_count': {
503→            // 略過 token 統計，太 noisy
504→            return '';
505→          }
506→
507→          case 'agent_reasoning': {
508→            // 與 response_item.reasoning 重複，略過
509→            return '';
510→          }
511→
512→          // 略過其他事件
513→          default:
514→            return '';
515→        }
516→      }
517→
518→      // 略過 turn_context
519→      case 'turn_context':
520→        return '';
521→
522→      default:
523→        return '';
524→    }
525→  }
526→}
