528→/**
529→ * Codex Agent
530→ */
531→export class CodexAgent implements Agent {
532→  readonly type = 'codex' as const;
533→  readonly finder: SessionFinder;
534→  readonly parser: LineParser;
535→
536→  constructor(options: ParserOptions = { verbose: false }) {
537→    this.finder = new CodexSessionFinder();
538→    this.parser = new CodexLineParser(options);
539→  }
540→}
