  1→import { stat, readFile, writeFile, mkdir } from 'node:fs/promises';
  2→import { homedir } from 'node:os';
  3→import { basename, dirname, join } from 'node:path';
  4→import { Glob } from 'bun';
  5→import type { SessionFile } from '../../core/types.ts';
  6→
  7→/**
  8→ * 快取中的 session 記錄
  9→ */
 10→interface CachedSession {
 11→  path: string;
 12→  mtime: number; // timestamp
 13→  cwd: string;
 14→}
 15→
 16→/**
 17→ * 快取檔案格式
 18→ */
 19→interface CacheFile {
 20→  version: number;
 21→  lastScanTime: number;
 22→  sessions: CachedSession[];
 23→}
 24→
 25→const CACHE_VERSION = 1;
 26→const CACHE_FILE_NAME = '.agent-tail-cache.json';
 27→
 28→/** 快取刷新間隔（毫秒）- 用於偵測新的 session */
 29→const CACHE_REFRESH_INTERVAL_MS = 2000;
 30→
 31→/**
 32→ * Codex Session 快取
 33→ * - 啟動時掃描所有 session，建立 cwd → sessions 的索引
 34→ * - 持久化快取到 ~/.codex/.agent-tail-cache.json
 35→ * - 使用 mtime 判斷是否需要更新
 36→ */
 37→export class CodexSessionCache {
 38→  private baseDir: string;
 39→  private cacheFile: string;
 40→  private cache: Map<string, CachedSession[]> = new Map();
 41→  private initialized = false;
 42→  private initPromise: Promise<void> | null = null;
 43→  private lastRefreshTime = 0;
 44→
 45→  constructor(baseDir?: string) {
 46→    this.baseDir = baseDir ?? join(homedir(), '.codex', 'sessions');
 47→    this.cacheFile = join(dirname(this.baseDir), CACHE_FILE_NAME);
 48→  }
 49→
 50→  /**
 51→   * 初始化快取（懶加載）
 52→   */
 53→  async init(): Promise<void> {
 54→    if (this.initialized) return;
 55→
 56→    // 防止並發初始化
 57→    if (this.initPromise) {
 58→      return this.initPromise;
 59→    }
 60→
 61→    this.initPromise = this.doInit();
 62→    await this.initPromise;
 63→    this.initPromise = null;
 64→  }
 65→
 66→  private async doInit(): Promise<void> {
 67→    // 嘗試從磁碟載入快取
 68→    const loaded = await this.loadFromDisk();
 69→    if (loaded) {
 70→      this.initialized = true;
 71→      return;
 72→    }
 73→
 74→    // 快取不存在或過期，重新掃描
 75→    await this.scanAllSessions();
 76→    await this.saveToDisk();
 77→    this.initialized = true;
 78→  }
 79→
 80→  /**
 81→   * 從磁碟載入快取
 82→   */
 83→  private async loadFromDisk(): Promise<boolean> {
 84→    try {
 85→      const content = await readFile(this.cacheFile, 'utf-8');
 86→      const data: CacheFile = JSON.parse(content);
 87→
 88→      if (data.version !== CACHE_VERSION) {
 89→        return false;
 90→      }
 91→
 92→      // 重建索引
 93→      this.cache.clear();
 94→      for (const session of data.sessions) {
 95→        if (!this.cache.has(session.cwd)) {
 96→          this.cache.set(session.cwd, []);
 97→        }
 98→        this.cache.get(session.cwd)!.push(session);
 99→      }
100→
101→      // 每個 cwd 內按 mtime 排序（降序）
102→      for (const [, sessions] of this.cache) {
103→        sessions.sort((a, b) => b.mtime - a.mtime);
104→      }
105→
106→      return true;
107→    } catch {
108→      return false;
109→    }
110→  }
111→
112→  /**
113→   * 儲存快取到磁碟
114→   */
115→  private async saveToDisk(): Promise<void> {
116→    try {
117→      const sessions: CachedSession[] = [];
118→      for (const [, cwdSessions] of this.cache) {
119→        sessions.push(...cwdSessions);
120→      }
121→
122→      const data: CacheFile = {
123→        version: CACHE_VERSION,
124→        lastScanTime: Date.now(),
125→        sessions,
126→      };
127→
128→      // 確保目錄存在
129→      await mkdir(dirname(this.cacheFile), { recursive: true });
130→      await writeFile(this.cacheFile, JSON.stringify(data, null, 2));
131→    } catch {
132→      // 忽略寫入錯誤
133→    }
134→  }
135→
136→  /**
137→   * 掃描所有 session 檔案，建立索引
138→   */
139→  private async scanAllSessions(): Promise<void> {
140→    const glob = new Glob('**/*.jsonl');
141→    const sessions: CachedSession[] = [];
142→
143→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
144→      const filename = basename(file);
145→      if (!filename.startsWith('rollout-')) continue;
146→
147→      try {
148→        // 只讀取第一行（session_meta）
149→        const content = await Bun.file(file).text();
150→        const firstLine = content.split('\n')[0];
151→        if (!firstLine) continue;
152→
153→        const meta = JSON.parse(firstLine);
154→        if (meta.type === 'session_meta' && meta.payload?.cwd) {
155→          const stats = await stat(file);
156→          sessions.push({
157→            path: file,
158→            mtime: stats.mtime.getTime(),
159→            cwd: meta.payload.cwd,
160→          });
161→        }
162→      } catch {
163→        // 忽略無法解析的檔案
164→      }
165→    }
166→
167→    // 建立 cwd 索引
168→    this.cache.clear();
169→    for (const session of sessions) {
170→      if (!this.cache.has(session.cwd)) {
171→        this.cache.set(session.cwd, []);
172→      }
173→      this.cache.get(session.cwd)!.push(session);
174→    }
175→
176→    // 每個 cwd 內按 mtime 排序（降序）
177→    for (const [, cwdSessions] of this.cache) {
178→      cwdSessions.sort((a, b) => b.mtime - a.mtime);
179→    }
180→  }
181→
182→  /**
183→   * 取得指定 cwd 的最新 session
184→   * 會驗證檔案是否存在，若不存在則嘗試下一個
185→   * 定期刷新以偵測新的 session
186→   */
187→  async getLatestByCwd(cwd: string): Promise<SessionFile | null> {
188→    await this.init();
189→
190→    // 檢查是否需要刷新（增量更新）
191→    await this.maybeRefresh();
192→
193→    const sessions = this.cache.get(cwd);
194→    if (!sessions || sessions.length === 0) return null;
195→
196→    // 找到第一個存在且有效的 session
197→    for (const session of sessions) {
198→      // 驗證檔案是否存在
199→      const file = Bun.file(session.path);
200→      if (await file.exists()) {
201→        return {
202→          path: session.path,
203→          mtime: new Date(session.mtime),
204→          agentType: 'codex',
205→        };
206→      }
207→    }
208→
209→    return null;
210→  }
211→
212→  /**
213→   * 檢查是否需要刷新快取（根據時間間隔）
214→   * 如果需要，掃描最近的 session 進行增量更新
215→   */
216→  private async maybeRefresh(): Promise<void> {
217→    const now = Date.now();
218→    if (now - this.lastRefreshTime < CACHE_REFRESH_INTERVAL_MS) {
219→      return;
220→    }
221→
222→    this.lastRefreshTime = now;
223→
224→    // 增量刷新：只掃描今天的 session
225→    const today = new Date();
226→    const year = today.getFullYear().toString();
227→    const month = (today.getMonth() + 1).toString().padStart(2, '0');
228→    const day = today.getDate().toString().padStart(2, '0');
229→    const todayDir = join(this.baseDir, year, month, day);
230→
231→    // 檢查今天的目錄是否存在（使用 stat 而非 Bun.file）
232→    try {
233→      const dirStats = await stat(todayDir);
234→      if (!dirStats.isDirectory()) return;
235→    } catch {
236→      return;
237→    }
238→
239→    // 掃描今天的 session
240→    const glob = new Glob('rollout-*.jsonl');
241→    for await (const file of glob.scan({ cwd: todayDir, absolute: true })) {
242→      const filename = basename(file);
243→      if (!filename.startsWith('rollout-')) continue;
244→
245→      try {
246→        // 檢查是否已在快取中
247→        let alreadyCached = false;
248→        for (const [, sessions] of this.cache) {
249→          if (sessions.some((s) => s.path === file)) {
250→            alreadyCached = true;
251→            break;
252→          }
253→        }
254→        if (alreadyCached) continue;
255→
256→        // 只讀取第一行（session_meta）
257→        const content = await Bun.file(file).text();
258→        const firstLine = content.split('\n')[0];
259→        if (!firstLine) continue;
260→
261→        const meta = JSON.parse(firstLine);
262→        if (meta.type === 'session_meta' && meta.payload?.cwd) {
263→          const stats = await stat(file);
264→          const newSession: CachedSession = {
265→            path: file,
266→            mtime: stats.mtime.getTime(),
267→            cwd: meta.payload.cwd,
268→          };
269→
270→          if (!this.cache.has(newSession.cwd)) {
271→            this.cache.set(newSession.cwd, []);
272→          }
273→          this.cache.get(newSession.cwd)!.push(newSession);
274→
275→          // 重新排序該 cwd 的 sessions（降序）
276→          this.cache.get(newSession.cwd)!.sort((a, b) => b.mtime - a.mtime);
277→        }
278→      } catch {
279→        // 忽略無法解析的檔案
280→      }
281→    }
282→  }
283→
284→  /**
285→   * 列出所有已知專案
286→   */
287→  async getAllProjects(): Promise<string[]> {
288→    await this.init();
289→    return Array.from(this.cache.keys());
290→  }
291→
292→  /**
293→   * 清除快取（用於測試或強制刷新）
294→   */
295→  clear(): void {
296→    this.cache.clear();
297→    this.initialized = false;
298→  }
299→}
