 9→/**
10→ * 取得 session 的有效活動時間
11→ * 包含 main session 和其所有 subagent 的最新 mtime
12→ */
13→async function getSessionActivityTime(
14→  mainSessionPath: string,
15→  mainMtime: Date
16→): Promise<Date> {
17→  const sessionId = basename(mainSessionPath, '.jsonl');
18→  const projectDir = dirname(mainSessionPath);
19→  const subagentsDir = join(projectDir, sessionId, 'subagents');
20→
21→  let latestMtime = mainMtime;
22→
23→  try {
24→    const glob = new Glob('agent-*.jsonl');
25→    for await (const file of glob.scan({ cwd: subagentsDir, absolute: true })) {
26→      try {
27→        const stats = await stat(file);
28→        if (stats.mtime > latestMtime) {
29→          latestMtime = stats.mtime;
30→        }
31→      } catch {
32→        // 忽略無法讀取的檔案
33→      }
34→    }
35→  } catch {
36→    // subagents 目錄不存在時靜默忽略
37→  }
38→
39→  return latestMtime;
40→}
