42→/**
43→ * 在指定 projectDir 中找最新的 Claude main session（UUID.jsonl）
44→ */
45→export async function findLatestMainSessionInProject(
46→  projectDir: string
47→): Promise<SessionFile | null> {
48→  const glob = new Glob('*.jsonl');
49→  const files: { path: string; mtime: Date; activityTime: Date }[] = [];
50→
51→  for await (const file of glob.scan({ cwd: projectDir, absolute: true })) {
52→    const filename = file.split('/').pop() || '';
53→
54→    // 排除 agent-* 開頭
55→    if (filename.startsWith('agent-')) continue;
56→    if (!UUID_SESSION_PATTERN.test(filename)) continue;
57→
58→    try {
59→      const stats = await stat(file);
60→      const activityTime = await getSessionActivityTime(file, stats.mtime);
61→      files.push({ path: file, mtime: stats.mtime, activityTime });
62→    } catch {
63→      // 忽略無法讀取的檔案
64→    }
65→  }
66→
67→  if (files.length === 0) return null;
68→
69→  files.sort(
70→    (a, b) =>
71→      b.activityTime.getTime() - a.activityTime.getTime() ||
72→      a.path.localeCompare(b.path)
73→  );
74→  const latest = files[0];
75→  if (!latest) return null;
76→
77→  return {
78→    path: latest.path,
79→    mtime: latest.mtime,
80→    agentType: 'claude',
81→  };
82→}
