139→  private async scanAllSessions(): Promise<void> {
140→    const glob = new Glob('**/*.jsonl');
141→    const sessions: CachedSession[] = [];
142→
143→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
144→      const filename = basename(file);
145→      if (!filename.startsWith('rollout-')) continue;
146→
147→      try {
148→        // 只讀取第一行（session_meta）
149→        const content = await Bun.file(file).text();
150→        const firstLine = content.split('\n')[0];
151→        if (!firstLine) continue;
152→
153→        const meta = JSON.parse(firstLine);
154→        if (meta.type === 'session_meta' && meta.payload?.cwd) {
155→          const stats = await stat(file);
156→          sessions.push({
157→            path: file,
158→            mtime: stats.mtime.getTime(),
159→            cwd: meta.payload.cwd,
160→          });
161→        }
162→      } catch {
163→        // 忽略無法解析的檔案
164→      }
165→    }
166→
167→    // 建立 cwd 索引
168→    this.cache.clear();
169→    for (const session of sessions) {
170→      if (!this.cache.has(session.cwd)) {
171→        this.cache.set(session.cwd, []);
172→      }
173→      this.cache.get(session.cwd)!.push(session);
174→    }
175→
176→    // 每個 cwd 內按 mtime 排序（降序）
177→    for (const [, cwdSessions] of this.cache) {
178→      cwdSessions.sort((a, b) => b.mtime - a.mtime);
179→    }
180→  }
