196→      const content = await Bun.file(sessionPath).text();
197→      const firstLine = content.split('\n')[0];
198→      if (!firstLine) return null;
199→
200→      const meta = JSON.parse(firstLine);
201→      if (meta.type === 'session_meta' && meta.payload?.cwd) {
202→        return {
203→          projectDir: meta.payload.cwd,
204→          displayName: meta.payload.cwd,
205→        };
206→      }
207→    } catch {
208→      // 忽略解析錯誤
209→    }
210→    return null;
