214→   * 在指定專案範圍內找最新的 session（用於 auto-switch）
215→   * @param cwd - 專案目錄路徑
216→   */
217→  async findLatestInProject(cwd: string): Promise<SessionFile | null> {
218→    return this.cache.getLatestByCwd(cwd);
219→  }
