222→   * 找到 subagent 檔案
223→   * - 有 subagentId：用 UUID glob 在所有日期目錄查找
224→   * - 無 subagentId：從最新 session 掃描 subagent IDs，回傳最新的 subagent 檔案
225→   *
226→   * 已知限制：無 subagentId 時，findLatest() 不保證回傳主 session（可能回傳 subagent 檔案）。
227→   * 若 extractCodexSubagentIds 回傳空陣列，會回傳 null。
228→   */
229→  async findSubagent(options: {
230→    project?: string;
231→    subagentId?: string;
232→  }): Promise<SessionFile | null> {
233→    if (options.subagentId) {
234→      // 有 subagentId：用 UUID glob 精確查找
235→      return this._findSubagentById(options.subagentId, options.project);
236→    } else {
237→      // 無 subagentId：從最新 session 掃描 subagent IDs
238→      return this._findLatestSubagent(options.project);
239→    }
240→  }
241→
242→  /**
243→   * 依 subagentId（UUID 前綴或完整 UUID）在所有日期目錄查找 subagent 檔案
244→   */
245→  private async _findSubagentById(
246→    subagentId: string,
247→    project?: string
248→  ): Promise<SessionFile | null> {
249→    const glob = new Glob('**/*.jsonl');
250→    const candidates: { path: string; mtime: Date }[] = [];
251→
252→    for await (const file of glob.scan({
253→      cwd: this._baseDir,
254→      absolute: true,
255→    })) {
256→      const filename = file.split('/').pop() || '';
257→      if (!filename.startsWith('rollout-')) continue;
258→
259→      // project filter
260→      if (project) {
261→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
262→      }
263→
264→      // 包含 subagentId（大小寫不敏感）
265→      if (!filename.toLowerCase().includes(subagentId.toLowerCase())) continue;
266→
267→      try {
268→        const stats = await stat(file);
269→        candidates.push({ path: file, mtime: stats.mtime });
270→      } catch {
271→        // 忽略無法讀取的檔案
272→      }
