284→  /**
285→   * 掃描所有 session，從最新的開始找第一個含 subagent IDs 的，回傳最新的 subagent 檔案
286→   *
287→   * 注意：findLatest() 不區分主 session 和 subagent session（依 mtime 排序）。
288→   * 此方法改為迭代所有候選 session，跳過不含 spawn_agent 事件的（通常是 subagent 本身）。
289→   */
290→  private async _findLatestSubagent(
291→    project?: string
292→  ): Promise<SessionFile | null> {
293→    const glob = new Glob('**/*.jsonl');
294→    const candidates: { path: string; mtime: Date }[] = [];
295→
296→    for await (const file of glob.scan({
297→      cwd: this._baseDir,
298→      absolute: true,
299→    })) {
300→      const filename = file.split('/').pop() || '';
301→      if (!filename.startsWith('rollout-')) continue;
302→
303→      if (project) {
304→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
305→      }
306→
307→      try {
308→        const stats = await stat(file);
309→        candidates.push({ path: file, mtime: stats.mtime });
310→      } catch {
311→        // 忽略無法讀取的檔案
312→      }
313→    }
314→
315→    if (candidates.length === 0) return null;
316→
317→    // 由新到舊排序，優先從最新的 session 找 subagent
318→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
319→
320→    for (const candidate of candidates) {
321→      const agentIds = await extractCodexSubagentIds(candidate.path);
322→      if (agentIds.length === 0) continue;
323→
324→      const dateDir = dirname(candidate.path);
325→      const subFiles = await buildCodexSubagentFiles(dateDir, agentIds);
326→      if (subFiles.length === 0) continue;
327→
328→      subFiles.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
329→      return subFiles[0] ?? null;
330→    }
331→
332→    return null;
333→  }
334→}
