    39→   * 同時會重置 cache 使用新的目錄
    40→   */
    41→  setBaseDir(dir: string): void {
    42→    this._baseDir = dir;
    43→    this._cache = new CodexSessionCache(dir);
    44→  }
    45→
    46→  /**
    47→   * 取得 cache 實例（用於 findLatestInProject）
    48→   */
    49→  private get cache(): CodexSessionCache {
