    53→  async findLatest(options: { project?: string }): Promise<SessionFile | null> {
    54→    const glob = new Glob('**/*.jsonl');
    55→    const files: { path: string; mtime: Date }[] = [];
    56→
    57→    for await (const file of glob.scan({
    58→      cwd: this._baseDir,
    59→      absolute: true,
    60→    })) {
    61→      // 只匹配 rollout-*.jsonl
    62→      const filename = file.split('/').pop() || '';
    63→      if (!filename.startsWith('rollout-')) continue;
    64→
    65→      // 如果有 project filter，做模糊比對（對 Codex 來說是日期過濾）
    66→      if (options.project) {
    67→        const pattern = options.project.toLowerCase();
    68→        if (!file.toLowerCase().includes(pattern)) continue;
    69→      }
    70→
    71→      try {
    72→        // 排除 subagent session
    73→        const content = await Bun.file(file).text();
    74→        const firstLine = content.split('\n')[0];
    75→        if (firstLine) {
    76→          const meta = JSON.parse(firstLine);
    77→          if (isSubagentMeta(meta)) continue;
    78→        }
    79→
    80→        const stats = await stat(file);
    81→        files.push({ path: file, mtime: stats.mtime });
    82→      } catch {
    83→        // 忽略無法讀取的檔案
    84→      }
    85→    }
    86→
    87→    if (files.length === 0) return null;
    88→
    89→    // 按修改時間排序，取最新的
    90→    files.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
    91→
    92→    const latest = files[0];
    93→    if (!latest) return null;
    94→
    95→    return {
    96→      path: latest.path,
    97→      mtime: latest.mtime,
    98→      agentType: 'codex',
    99→    };
   100→  }
   101→
   102→  /**
   103→   * 依 session ID 查找 session 檔案
   104→   * 檔名格式：rollout-{timestamp}-{sessionId}.jsonl
   105→   * 支援匹配：session ID（ULID）、時間戳
   106→   */
   107→  async findBySessionId(
   108→    sessionId: string,
   109→    options: { project?: string }
   110→  ): Promise<SessionFile | null> {
   111→    const glob = new Glob('**/*.jsonl');
   112→    const candidates: { path: string; mtime: Date; priority: number }[] = [];
   113→
   114→    // UUID 格式的正規表達式（用於提取 session ID）
   115→    const ulidPattern =
   116→      /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})\.jsonl$/i;
   117→
   118→    for await (const file of glob.scan({
   119→      cwd: this._baseDir,
   120→      absolute: true,
   121→    })) {
   122→      const filename = file.split('/').pop() || '';
   123→      if (!filename.startsWith('rollout-')) continue;
   124→
   125→      // project filter
   126→      if (options.project) {
   127→        const pattern = options.project.toLowerCase();
   128→        if (!file.toLowerCase().includes(pattern)) continue;
   129→      }
   130→
   131→      // 從檔名提取 session ID（ULID 部分）
   132→      const ulidMatch = filename.match(ulidPattern);
   133→      const extractedSessionId = ulidMatch?.[1] || '';
   134→
   135→      // 提取時間戳部分（rollout- 和 session ID 之間的部分）
   136→      // rollout-2025-11-03T20-42-15-019a49bd-...
   137→      const withoutPrefix = filename.replace(/^rollout-/, '');
   138→      const timestampPart = extractedSessionId
   139→        ? withoutPrefix.replace(`-${extractedSessionId}.jsonl`, '')
   140→        : '';
   141→
   142→      // 計算匹配優先級
   143→      let priority = 0;
   144→      const searchTerm = sessionId.toLowerCase();
   145→
   146→      // 1. 對 session ID 進行匹配
   147→      if (extractedSessionId) {
   148→        const normalizedId = extractedSessionId.toLowerCase();
   149→        if (normalizedId === searchTerm) {
   150→          priority = 6; // 精確匹配 session ID
   151→        } else if (normalizedId.startsWith(searchTerm)) {
   152→          priority = 5; // 前綴匹配 session ID
   153→        } else if (normalizedId.includes(searchTerm)) {
   154→          priority = 4; // 包含匹配 session ID
   155→        }
   156→      }
   157→
   158→      // 2. 對時間戳進行匹配（如果 session ID 沒有匹配到）
   159→      if (priority === 0 && timestampPart) {
   160→        const normalizedTimestamp = timestampPart.toLowerCase();
   161→        if (normalizedTimestamp === searchTerm) {
   162→          priority = 3; // 精確匹配時間戳
   163→        } else if (normalizedTimestamp.startsWith(searchTerm)) {
   164→          priority = 2; // 前綴匹配時間戳
   165→        } else if (normalizedTimestamp.includes(searchTerm)) {
   166→          priority = 1; // 包含匹配時間戳
   167→        }
   168→      }
   169→
   170→      if (priority === 0) continue;
   171→
   172→      try {
   173→        const stats = await stat(file);
   174→        candidates.push({ path: file, mtime: stats.mtime, priority });
   175→      } catch {
   176→        // 忽略無法讀取的檔案
   177→      }
   178→    }
   179→
   180→    if (candidates.length === 0) return null;
   181→
   182→    // 排序：優先級降序 > mtime 降序
   183→    candidates.sort((a, b) => {
   184→      if (b.priority !== a.priority) return b.priority - a.priority;
   185→      return b.mtime.getTime() - a.mtime.getTime();
   186→    });
   187→
   188→    const best = candidates[0];
   189→    if (!best) return null;
   190→
   191→    return {
   192→      path: best.path,
   193→      mtime: best.mtime,
   194→      agentType: 'codex',
   195→    };
   196→  }
