   250→  /**
   251→   * 依 subagentId（UUID 前綴或完整 UUID）在所有日期目錄查找 subagent 檔案
   252→   */
   253→  private async _findSubagentById(
   254→    subagentId: string,
   255→    project?: string
   256→  ): Promise<SessionFile | null> {
   257→    const glob = new Glob('**/*.jsonl');
   258→    const candidates: { path: string; mtime: Date }[] = [];
   259→
   260→    for await (const file of glob.scan({
   261→      cwd: this._baseDir,
