   263→    })) {
   264→      const filename = file.split('/').pop() || '';
   265→      if (!filename.startsWith('rollout-')) continue;
   266→
   267→      // project filter
   268→      if (project) {
   269→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
   270→      }
   271→
   272→      // 包含 subagentId（大小寫不敏感）
   273→      if (!filename.toLowerCase().includes(subagentId.toLowerCase())) continue;
   274→
   275→      try {
   276→        const stats = await stat(file);
   277→        candidates.push({ path: file, mtime: stats.mtime });
   278→      } catch {
   279→        // 忽略無法讀取的檔案
   280→      }
   281→    }
   282→
   283→    if (candidates.length === 0) return null;
   284→
   285→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
   286→    const best = candidates[0];
   287→    if (!best) return null;
