   292→  /**
   293→   * 掃描所有 session，從最新的開始找第一個含 subagent IDs 的，回傳最新的 subagent 檔案
   294→   *
   295→   * 注意：findLatest() 不區分主 session 和 subagent session（依 mtime 排序）。
   296→   * 此方法改為迭代所有候選 session，跳過不含 spawn_agent 事件的（通常是 subagent 本身）。
   297→   */
   298→  private async _findLatestSubagent(
   299→    project?: string
   300→  ): Promise<SessionFile | null> {
   301→    const glob = new Glob('**/*.jsonl');
   302→    const candidates: { path: string; mtime: Date }[] = [];
   303→
   304→    for await (const file of glob.scan({
   305→      cwd: this._baseDir,
   306→      absolute: true,
   307→    })) {
   308→      const filename = file.split('/').pop() || '';
   309→      if (!filename.startsWith('rollout-')) continue;
   310→
   311→      if (project) {
   312→        if (!file.toLowerCase().includes(project.toLowerCase())) continue;
   313→      }
   314→
   315→      try {
   316→        const stats = await stat(file);
   317→        candidates.push({ path: file, mtime: stats.mtime });
   318→      } catch {
   319→        // 忽略無法讀取的檔案
   320→      }
   321→    }
   322→
   323→    if (candidates.length === 0) return null;
   324→
   325→    // 由新到舊排序，優先從最新的 session 找 subagent
   326→    candidates.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
   327→
   328→    for (const candidate of candidates) {
   329→      const agentIds = await extractCodexSubagentIds(candidate.path);
   330→      if (agentIds.length === 0) continue;
   331→
   332→      const dateDir = dirname(candidate.path);
   333→      const subFiles = await buildCodexSubagentFiles(dateDir, agentIds);
   334→      if (subFiles.length === 0) continue;
   335→
   336→      subFiles.sort((a, b) => b.mtime.getTime() - a.mtime.getTime());
   337→      return subFiles[0] ?? null;
   338→    }
   339→
   340→    return null;
   341→  }
   342→}
