   344→/**
   345→ * Codex JSONL 解析器
   346→ */
   347→class CodexLineParser implements LineParser {
   348→  private verbose: boolean;
   349→
   350→  constructor(options: ParserOptions = { verbose: false }) {
   351→    this.verbose = options.verbose;
   352→  }
   353→
   354→  parse(line: string): ParsedLine | null {
   355→    if (!line.trim()) return null;
   356→
   357→    try {
   358→      const data = JSON.parse(line);
   359→      const timestamp = data.timestamp || '';
   360→      const formatted = this.format(data);
   361→
   362→      // 空內容不輸出
   363→      if (!formatted) return null;
   364→
   365→      // 決定顯示類型
   366→      const type = this.getDisplayType(data);
   367→
   368→      // 取得 tool name（僅 function_call 類型）
   369→      const toolName = this.getToolName(data);
   370→
   371→      return {
   372→        type,
   373→        timestamp,
   374→        raw: data,
   375→        formatted,
   376→        ...(toolName && { toolName }),
   377→      };
   378→    } catch {
   379→      return null;
   380→    }
   381→  }
   382→
   383→  /**
   384→   * 取得 tool 名稱（僅 function_call 類型）
   385→   */
   386→  private getToolName(data: Record<string, unknown>): string | undefined {
   387→    const type = data.type as string;
   388→    if (type !== 'response_item') return undefined;
   389→
   390→    const payload = data.payload as Record<string, unknown>;
   391→    if (payload.type !== 'function_call') return undefined;
   392→
   393→    return payload.name as string | undefined;
   394→  }
   395→
   396→  /**
   397→   * 根據資料內容決定顯示類型
   398→   */
   399→  private getDisplayType(data: Record<string, unknown>): string {
   400→    const type = data.type as string;
   401→
   402→    if (type === 'session_meta') return 'session_meta';
   403→
   404→    if (type === 'response_item') {
   405→      const payload = data.payload as Record<string, unknown>;
   406→      const subType = payload.type as string;
   407→
   408→      if (subType === 'message') {
   409→        const role = payload.role as string;
   410→        return role || 'message';
   411→      }
   412→      if (subType === 'function_call') return 'function_call';
   413→      if (subType === 'function_call_output') return 'output';
   414→      if (subType === 'reasoning') return 'reasoning';
   415→    }
   416→
   417→    return type || 'unknown';
   418→  }
   419→
   420→  private format(data: Record<string, unknown>): string {
   421→    const type = data.type as string;
   422→
   423→    switch (type) {
   424→      case 'session_meta': {
   425→        const payload = data.payload as Record<string, unknown>;
   426→        return `Session: ${payload.cwd || 'unknown'} (v${payload.cli_version || '?'})`;
   427→      }
   428→
   429→      case 'response_item': {
   430→        const payload = data.payload as Record<string, unknown>;
   431→        const subType = payload.type as string;
   432→
   433→        switch (subType) {
   434→          case 'message': {
   435→            const _role = payload.role as string;
   436→            const content = payload.content as Array<{
   437→              type: string;
   438→              text?: string;
   439→            }>;
   440→            const text =
   441→              content?.find(
   442→                (c) => c.type === 'input_text' || c.type === 'output_text'
   443→              )?.text || '';
   444→            if (!text.trim()) return '';
   445→            const preview = truncateByLines(text, { verbose: this.verbose });
   446→            // 不再重複顯示 role，由 pretty-formatter 處理
   447→            return formatMultiline(preview);
   448→          }
   449→
   450→          case 'function_call': {
   451→            const name = payload.name as string;
   452→            const argsStr = payload.arguments as string;
   453→            let args: Record<string, unknown> = {};
   454→            try {
   455→              args = JSON.parse(argsStr);
   456→            } catch {
   457→              /* ignore */
   458→            }
   459→            return formatToolUse(name, args, { verbose: this.verbose });
   460→          }
   461→
   462→          case 'function_call_output': {
   463→            const outputStr = payload.output as string;
   464→            let output: { output?: string; metadata?: { exit_code?: number } } =
   465→              {};
   466→            try {
   467→              output = JSON.parse(outputStr);
   468→            } catch {
   469→              /* ignore */
   470→            }
   471→            const exitCode = output.metadata?.exit_code;
   472→            const content = output.output || '';
   473→            // 沒內容且 exit code 正常就不顯示
   474→            if (!content && (exitCode === undefined || exitCode === 0))
   475→              return '';
   476→            const exitInfo =
   477→              exitCode !== undefined && exitCode !== 0
   478→                ? ` (exit: ${exitCode})`
   479→                : '';
   480→            if (!content) return `[OUTPUT${exitInfo}]`;
   481→            const preview = truncateByLines(content, { verbose: this.verbose });
   482→            return `${exitInfo ? `[exit: ${exitCode}]` : ''}${formatMultiline(preview)}`;
   483→          }
   484→
   485→          case 'reasoning': {
   486→            const summary = payload.summary as
   487→              | Array<{ type: string; text?: string }>
   488→              | undefined;
   489→            const text =
   490→              summary?.find((s) => s.type === 'summary_text')?.text || '';
   491→            if (!text) return '';
   492→            const preview = truncateByLines(text, { verbose: this.verbose });
   493→            return preview;
   494→          }
   495→
   496→          // 忽略的子類型
   497→          case 'ghost_snapshot':
   498→            return '';
   499→
   500→          default:
   501→            return '';
   502→        }
   503→      }
   504→
   505→      case 'event_msg': {
   506→        const payload = data.payload as Record<string, unknown>;
   507→        const eventType = payload.type as string;
   508→
   509→        switch (eventType) {
   510→          case 'token_count': {
   511→            // 略過 token 統計，太 noisy
   512→            return '';
   513→          }
   514→
   515→          case 'agent_reasoning': {
   516→            // 與 response_item.reasoning 重複，略過
   517→            return '';
   518→          }
   519→
   520→          // 略過其他事件
   521→          default:
   522→            return '';
   523→        }
   524→      }
   525→
   526→      // 略過 turn_context
   527→      case 'turn_context':
   528→        return '';
   529→
   530→      default:
   531→        return '';
   532→    }
   533→  }
   534→}
