    81→    if (loaded) {
    82→      this.initialized = true;
    83→      return;
    84→    }
    85→
    86→    // 快取不存在或過期，重新掃描
    87→    await this.scanAllSessions();
    88→    await this.saveToDisk();
    89→    this.initialized = true;
    90→  }
    91→
    92→  /**
    93→   * 從磁碟載入快取
    94→   */
    95→  private async loadFromDisk(): Promise<boolean> {
    96→    try {
    97→      const content = await readFile(this.cacheFile, 'utf-8');
    98→      const data: CacheFile = JSON.parse(content);
    99→
   100→      if (data.version !== CACHE_VERSION) {
   101→        return false;
   102→      }
   103→
   104→      // 重建索引
   105→      this.cache.clear();
   106→      for (const session of data.sessions) {
   107→        if (!this.cache.has(session.cwd)) {
   108→          this.cache.set(session.cwd, []);
   109→        }
   110→        this.cache.get(session.cwd)!.push(session);
   111→      }
   112→
   113→      // 每個 cwd 內按 mtime 排序（降序）
   114→      for (const [, sessions] of this.cache) {
   115→        sessions.sort((a, b) => b.mtime - a.mtime);
   116→      }
   117→
   118→      return true;
   119→    } catch {
   120→      return false;
   121→    }
   122→  }
   123→
   124→  /**
   125→   * 儲存快取到磁碟
   126→   */
   127→  private async saveToDisk(): Promise<void> {
   128→    try {
   129→      const sessions: CachedSession[] = [];
   130→      for (const [, cwdSessions] of this.cache) {
   131→        sessions.push(...cwdSessions);
   132→      }
   133→
   134→      const data: CacheFile = {
   135→        version: CACHE_VERSION,
   136→        lastScanTime: Date.now(),
   137→        sessions,
   138→      };
   139→
   140→      // 確保目錄存在
   141→      await mkdir(dirname(this.cacheFile), { recursive: true });
   142→      await writeFile(this.cacheFile, JSON.stringify(data, null, 2));
   143→    } catch {
   144→      // 忽略寫入錯誤
   145→    }
   146→  }
   147→
   148→  /**
   149→   * 掃描所有 session 檔案，建立索引
   150→   */
   151→  private async scanAllSessions(): Promise<void> {
   152→    const glob = new Glob('**/*.jsonl');
   153→    const sessions: CachedSession[] = [];
   154→
   155→    for await (const file of glob.scan({ cwd: this.baseDir, absolute: true })) {
   156→      const filename = basename(file);
   157→      if (!filename.startsWith('rollout-')) continue;
   158→
   159→      try {
   160→        // 只讀取第一行（session_meta）
   161→        const content = await Bun.file(file).text();
   162→        const firstLine = content.split('\n')[0];
   163→        if (!firstLine) continue;
   164→
   165→        const meta = JSON.parse(firstLine);
   166→        if (meta.type === 'session_meta' && meta.payload?.cwd) {
   167→          // 排除 subagent session（source 為物件且含 subagent 屬性）
   168→          if (isSubagentMeta(meta)) continue;
   169→
   170→          const stats = await stat(file);
   171→          sessions.push({
   172→            path: file,
   173→            mtime: stats.mtime.getTime(),
   174→            cwd: meta.payload.cwd,
   175→          });
   176→        }
   177→      } catch {
   178→        // 忽略無法解析的檔案
   179→      }
   180→    }
   181→
   182→    // 建立 cwd 索引
   183→    this.cache.clear();
   184→    for (const session of sessions) {
   185→      if (!this.cache.has(session.cwd)) {
   186→        this.cache.set(session.cwd, []);
   187→      }
   188→      this.cache.get(session.cwd)!.push(session);
   189→    }
   190→
   191→    // 每個 cwd 內按 mtime 排序（降序）
   192→    for (const [, cwdSessions] of this.cache) {
   193→      cwdSessions.sort((a, b) => b.mtime - a.mtime);
   194→    }
   195→  }
   196→
   197→  /**
   198→   * 取得指定 cwd 的最新 session
   199→   * 會驗證檔案是否存在，若不存在則嘗試下一個
   200→   * 定期刷新以偵測新的 session
   201→   */
   202→  async getLatestByCwd(cwd: string): Promise<SessionFile | null> {
   203→    await this.init();
   204→
   205→    // 檢查是否需要刷新（增量更新）
   206→    await this.maybeRefresh();
   207→
   208→    const sessions = this.cache.get(cwd);
   209→    if (!sessions || sessions.length === 0) return null;
   210→
   211→    // 找到第一個存在且有效的 session
   212→    for (const session of sessions) {
   213→      // 驗證檔案是否存在
   214→      const file = Bun.file(session.path);
   215→      if (await file.exists()) {
   216→        return {
   217→          path: session.path,
   218→          mtime: new Date(session.mtime),
   219→          agentType: 'codex',
   220→        };
   221→      }
   222→    }
   223→
   224→    return null;
   225→  }
   226→
   227→  /**
   228→   * 檢查是否需要刷新快取（根據時間間隔）
   229→   * 如果需要，掃描最近的 session 進行增量更新
   230→   */
   231→  private async maybeRefresh(): Promise<void> {
   232→    const now = Date.now();
   233→    if (now - this.lastRefreshTime < CACHE_REFRESH_INTERVAL_MS) {
   234→      return;
   235→    }
   236→
   237→    this.lastRefreshTime = now;
   238→
   239→    // 增量刷新：只掃描今天的 session
   240→    const today = new Date();
   241→    const year = today.getFullYear().toString();
   242→    const month = (today.getMonth() + 1).toString().padStart(2, '0');
   243→    const day = today.getDate().toString().padStart(2, '0');
   244→    const todayDir = join(this.baseDir, year, month, day);
   245→
   246→    // 檢查今天的目錄是否存在（使用 stat 而非 Bun.file）
   247→    try {
   248→      const dirStats = await stat(todayDir);
   249→      if (!dirStats.isDirectory()) return;
   250→    } catch {
   251→      return;
   252→    }
   253→
   254→    // 掃描今天的 session
   255→    const glob = new Glob('rollout-*.jsonl');
   256→    for await (const file of glob.scan({ cwd: todayDir, absolute: true })) {
   257→      const filename = basename(file);
   258→      if (!filename.startsWith('rollout-')) continue;
   259→
   260→      try {
   261→        // 檢查是否已在快取中
   262→        let alreadyCached = false;
   263→        for (const [, sessions] of this.cache) {
   264→          if (sessions.some((s) => s.path === file)) {
   265→            alreadyCached = true;
   266→            break;
   267→          }
   268→        }
   269→        if (alreadyCached) continue;
   270→
   271→        // 只讀取第一行（session_meta）
   272→        const content = await Bun.file(file).text();
   273→        const firstLine = content.split('\n')[0];
   274→        if (!firstLine) continue;
   275→
   276→        const meta = JSON.parse(firstLine);
   277→        if (meta.type === 'session_meta' && meta.payload?.cwd) {
   278→          // 排除 subagent session
   279→          if (isSubagentMeta(meta)) continue;
   280→
   281→          const stats = await stat(file);
   282→          const newSession: CachedSession = {
   283→            path: file,
   284→            mtime: stats.mtime.getTime(),
   285→            cwd: meta.payload.cwd,
   286→          };
   287→
   288→          if (!this.cache.has(newSession.cwd)) {
   289→            this.cache.set(newSession.cwd, []);
   290→          }
   291→          this.cache.get(newSession.cwd)!.push(newSession);
   292→
   293→          // 重新排序該 cwd 的 sessions（降序）
   294→          this.cache.get(newSession.cwd)!.sort((a, b) => b.mtime - a.mtime);
   295→        }
   296→      } catch {
   297→        // 忽略無法解析的檔案
   298→      }
   299→    }
   300→  }
   301→
   302→  /**
   303→   * 列出所有已知專案
   304→   */
   305→  async getAllProjects(): Promise<string[]> {
   306→    await this.init();
   307→    return Array.from(this.cache.keys());
   308→  }
   309→
   310→  /**
   311→   * 清除快取（用於測試或強制刷新）
   312→   */
   313→  clear(): void {
   314→    this.cache.clear();
   315→    this.initialized = false;
   316→  }
   317→}
