import { stat, readFile, writeFile, mkdir } from 'node:fs/promises';
import { homedir } from 'node:os';
import { basename, dirname, join } from 'node:path';
import { Glob } from 'bun';
import type { SessionFile } from '../../core/types.ts';

/**
 * 快取中的 session 記錄
 */
interface CachedSession {
  path: string;
  mtime: number; // timestamp
  cwd: string;
}

/**
 * 快取檔案格式
 */
interface CacheFile {
  version: number;
  lastScanTime: number;
  sessions: CachedSession[];
}

/**
 * 判斷 session_meta 是否屬於 subagent
 * Subagent 的 source 為物件 { subagent: { thread_spawn: ... } }
 * 主 session 的 source 為字串（如 "mcp"）
 */
export function isSubagentMeta(meta: {
  payload?: { source?: unknown };
}): boolean {
  const source = meta.payload?.source;
  return typeof source === 'object' && source !== null && 'subagent' in source;
}

const CACHE_VERSION = 1;
const CACHE_FILE_NAME = '.agent-tail-cache.json';

/** 快取刷新間隔（毫秒）- 用於偵測新的 session */

