        meta?.type === 'session_meta' &&
        meta.payload &&
        typeof meta.payload === 'object' &&
        'cwd' in meta.payload &&
        (meta.payload as Record<string, unknown>).cwd
      ) {
        // 排除 subagent session（source 為物件且含 subagent 屬性）
        if (isSubagentMeta(meta as { payload?: { source?: unknown } }))
